            ContentJson = """{"appRoute":"/scheduling","startButtonLabel":"Tour Scheduling","steps":[{"element":".scheduling__kpis","popover":{"title":"Scheduling KPIs","description":"These tiles give you a quick read on your plan. They show how many operations are scheduled, how many are running now, and how many work centers you have.","side":"bottom"}},{"element":".tab-bar","popover":{"title":"The Five Tabs","description":"Scheduling has five tabs. Schedule lists every planned operation. Dispatch shows what to run next at a work center. Work Centers holds your machines and stations. Shifts holds your operating hours. Run History records each time you ran the scheduler.","side":"bottom"}},{"element":"[data-testid='scheduling-run-btn']","popover":{"title":"Run Scheduler","description":"On the Schedule tab, click Run Scheduler to build the plan automatically. It places your jobs' operations onto work centers as early as there is room. Each run is saved in Run History with how many operations it scheduled and how many problems it found.","side":"bottom"}},{"element":".tab-bar .tab:first-child","popover":{"title":"The Schedule Tab","description":"This is the main view. It lists every scheduled operation, one per row, with the job, work center, start and end times, hours, status, and a lock. Click a column heading to sort, and use the gear to choose which columns show.","side":"bottom"}},{"element":".tab-panel app-toolbar","popover":{"title":"Lock an Operation","description":"Each row has a lock. Click it to pin that operation in place, so the scheduler works everything else around it and never moves it. Click again to unlock. Use this when an operation is already set up or promised.","side":"bottom"}},{"element":"[data-testid='work-center-create-btn']","popover":{"title":"New Work Center","description":"On the Work Centers tab, click New Work Center to add a machine or station. Enter its code, name, daily hours, efficiency, and number of machines. The scheduler uses these to figure out how much work the center can take.","side":"bottom"}},{"element":".tab-panel app-data-table","popover":{"title":"Work Centers Table","description":"Open the Work Centers tab to see every center in a table. Each row shows its code, name, daily capacity, efficiency, and whether it is active. Keeping this up to date makes the schedule match your shop's real capacity.","side":"bottom"}},{"element":".row-actions","popover":{"title":"Edit a Work Center","description":"Click the pencil on any row to reopen the same form, filled in with the current values. Editing also gives you an on/off switch to take a center out of scheduling without deleting it. Click Save Changes to keep them. Edit whenever a machine's capacity, efficiency, or rates change.","side":"left"}},{"element":".row-actions","popover":{"title":"Delete a Work Center","description":"Click the red trash icon to remove a work center. It does not delete right away. A window opens first, names the center, and asks you to confirm. This step protects you from removing a center that operations are still scheduled against.","side":"left"}}]}"""
