            ContentJson = """{"title":"Scheduling Field Reference","groups":[{"heading":"Tabs","items":[{"label":"Schedule","value":"Lists every scheduled operation, one per row, and lets you sort and filter. This is where you run the scheduler and lock operations. It opens by default."},{"label":"Dispatch","value":"Shows what to run next at one work center, in priority order. Pick a work center and click Load to fill the list."},{"label":"Work Centers","value":"Your machines and stations. Add, edit, or remove them here."},{"label":"Shifts","value":"A read-only list of your operating hours (start, end, breaks, net hours). Shifts are shared across all work centers."},{"label":"Run History","value":"A record of every scheduler run, with the date, how many operations it scheduled, and how many problems it found."}]},{"heading":"KPI Tiles (Top of Page)","items":[{"label":"Scheduled Ops","value":"How many operations are on the schedule."},{"label":"In Progress","value":"How many operations are running now."},{"label":"Work Centers","value":"How many work centers you have."}]},{"heading":"Work Center Fields","items":[{"label":"Code (required)","value":"A short identifier for the center, such as 'CNC-01'."},{"label":"Name (required)","value":"The full name, such as 'Machining Center'."},{"label":"Description","value":"An optional note about the center."},{"label":"Daily Capacity (Hours) (required)","value":"How many hours of work the center can take per day. The scheduler uses this to plan capacity."},{"label":"Efficiency % (required)","value":"How realistic the daily hours are. 100% means the center hits its full hours; lower values leave room for downtime and rework."},{"label":"Number of Machines (required)","value":"How many identical machines the center has that can run at the same time."},{"label":"Sort Order","value":"An optional number that sets where the center appears in the list."},{"label":"Labor Cost / Hour","value":"An optional labor rate, used for costing."},{"label":"Burden Rate / Hour","value":"An optional overhead rate, used for costing."},{"label":"Active","value":"An on/off switch, shown only when editing. Turn a center off to keep it out of scheduling."}]},{"heading":"Operation Statuses (Schedule Tab)","items":[{"label":"Scheduled","value":"The operation is on the schedule but has not started."},{"label":"In Progress","value":"The operation is running now."},{"label":"Complete","value":"The operation finished."},{"label":"Cancelled","value":"The operation was cancelled."}]},{"heading":"Run Statuses (Run History Tab)","items":[{"label":"Completed","value":"The scheduler run finished."},{"label":"Running","value":"The scheduler is running now."},{"label":"Failed","value":"The scheduler run hit an error."},{"label":"Queued","value":"The run is waiting to start."}]},{"heading":"Schedule Direction","items":[{"label":"Forward","value":"Plans from today onward, placing work as early as there is room."},{"label":"Backward","value":"Plans back from the due date, so work finishes just in time."}]},{"heading":"Schedule Tab Columns","items":[{"label":"Job #","value":"The job the operation belongs to. Click to sort."},{"label":"Operation","value":"The operation's name. Click to sort."},{"label":"Work Center","value":"The center the operation runs on. Sort and filter."},{"label":"Start / End","value":"The scheduled start and end. Click to sort."},{"label":"Hours","value":"Total scheduled hours for the operation. Click to sort."},{"label":"Status","value":"A colored label showing where the operation stands. Sort and filter."},{"label":"Locked","value":"A lock you can turn on or off. Locked operations stay put when the scheduler runs."}]},{"heading":"Dispatch Tab Columns","items":[{"label":"Job #","value":"The job for the operation. Click to sort."},{"label":"Operation","value":"The operation's name. Click to sort."},{"label":"Seq","value":"Where the operation falls in the queue. Click to sort."},{"label":"Start","value":"The scheduled start. Click to sort."},{"label":"Setup Hrs / Run Hrs","value":"Setup and run hours for the operation. Click to sort."},{"label":"Priority","value":"The job's priority. Click to sort."},{"label":"Due Date","value":"The job's due date. Click to sort."}]},{"heading":"Work Centers Tab Columns","items":[{"label":"Code / Name","value":"The center's short code and full name. Click to sort."},{"label":"Daily Cap","value":"Daily capacity in hours. Click to sort."},{"label":"Efficiency","value":"The center's efficiency percentage. Click to sort."},{"label":"Machines","value":"How many machines the center has. Click to sort."},{"label":"Active","value":"Whether the center is active. Click to sort."},{"label":"Asset / Location","value":"The linked equipment and location. Click to sort."},{"label":"Actions","value":"Buttons to edit or delete the center."}]},{"heading":"Shifts Tab Columns","items":[{"label":"Name","value":"The shift's name. Click to sort."},{"label":"Start Time / End Time","value":"When the shift begins and ends. Click to sort."},{"label":"Break Min","value":"Break minutes in the shift. Click to sort."},{"label":"Net Hours","value":"Working hours after breaks (end − start − breaks). Click to sort."},{"label":"Active","value":"Whether the shift is active. Click to sort."}]},{"heading":"Run History Tab Columns","items":[{"label":"Run Date","value":"When the run started. Click to sort."},{"label":"Direction","value":"Forward or backward. Click to sort."},{"label":"Status","value":"Whether the run completed, is running, or failed. Sort and filter."},{"label":"Ops Scheduled","value":"How many operations the run scheduled. Click to sort."},{"label":"Conflicts","value":"How many problems the run found. Click to sort."},{"label":"Completed","value":"When the run finished. Click to sort."}]},{"heading":"Buttons and Actions","items":[{"label":"Run Scheduler (Schedule tab)","value":"Builds the plan automatically."},{"label":"Lock / Unlock (Schedule tab row)","value":"Turns on or off whether the scheduler may move the operation."},{"label":"Work Center selector + Load (Dispatch tab)","value":"Pick a work center, then click Load to fill its queue. Load stays greyed out until you pick one."},{"label":"New Work Center (Work Centers tab)","value":"Opens the form to add a work center."},{"label":"Edit (Work Centers row)","value":"The pencil reopens the form for that center, filled in with its current values. Editing adds an on/off switch the add form doesn't show. Save Changes to keep them."},{"label":"Delete (Work Centers row)","value":"The red trash icon removes the center. It asks you to confirm first, naming the center, so you don't remove it by accident."},{"label":"Cancel / Save (form)","value":"Cancel closes without saving; Save keeps your changes. Save stays greyed out until the form is filled in correctly, and tells you what's missing."}]},{"heading":"Key Concepts","items":[{"label":"Capacity","value":"How much work a center can take, based on its daily hours, efficiency, number of machines, and shift hours."},{"label":"Conflict","value":"A problem the scheduler finds, most often a center given more work than it can handle."},{"label":"Lock","value":"A 'do not move' mark on an operation. The scheduler plans around it."},{"label":"Net Hours","value":"A shift's working hours: end − start − break minutes."},{"label":"Dispatch List","value":"The priority-ordered list of what to run next at one work center, for the person on the floor."}]}]}"""
